class Solution:
    def maximumTotalCost(self, nums) -> int:
        n = len(nums)
        if n == 0:
            return 0
        pos = nums[0]
        neg = float('-inf')
        for i in range(1, n):
            new_pos = max(pos, neg) + nums[i]
            new_neg = pos - nums[i]
            pos, neg = new_pos, new_neg
        return max(pos, neg)

