var maximumTotalCost = function(nums) {
    const n = nums.length;
    if (n === 0) return 0;
    let pos = nums[0], neg = -Infinity;
    for (let i = 1; i < n; i++) {
        const newPos = Math.max(pos, neg) + nums[i];
        const newNeg = pos - nums[i];
        pos = newPos;
        neg = newNeg;
    }
    return Math.max(pos, neg);
};
